#!/usr/bin/env python3
"""
MOI regression for simulated mechanisms using E9 WPILog data.

Physics:  G * n * kt * I  =  J * alpha  +  B * omega
Solve 2-parameter OLS for [J, B].

Conventions:
  - Flywheel/Kicker/Spindexer: logged as linear velocity (m/s), wheel radius r converts to angular
  - Turret: logged as angular velocity (rad/s) at output shaft directly
"""
import numpy as np


# ─── helpers ────────────────────────────────────────────────────────────────

def nearest_interp(ts_query, ts_ref, vals_ref):
    ts_query = np.asarray(ts_query, float)
    ts_ref   = np.asarray(ts_ref,   float)
    vals_ref = np.asarray(vals_ref, float)
    n = min(len(ts_ref), len(vals_ref))
    ts_ref, vals_ref = ts_ref[:n], vals_ref[:n]
    idx = np.searchsorted(ts_ref, ts_query).clip(0, n - 1)
    # compare with left neighbour
    left = (idx > 0)
    closer_left = left & (np.abs(ts_ref[idx-1] - ts_query) < np.abs(ts_ref[idx] - ts_query))
    idx[closer_left] -= 1
    return vals_ref[idx]


def smooth(vals, w):
    """Symmetric moving-average of half-width w samples."""
    kernel = np.ones(2*w+1) / (2*w+1)
    return np.convolve(vals, kernel, mode='same')


def ols(alpha, omega, torque, alpha_thresh, label):
    mask = np.abs(alpha) > alpha_thresh
    X = np.column_stack([alpha[mask], omega[mask]])
    y = torque[mask]
    # remove non-finite
    ok = np.isfinite(X).all(1) & np.isfinite(y)
    X, y = X[ok], y[ok]
    if len(y) < 10:
        print(f"  [{label}] insufficient samples after filter: {len(y)}")
        return None, None, None
    sol, *_ = np.linalg.lstsq(X, y, rcond=None)
    J, B = sol
    y_hat = X @ sol
    ss_res = np.sum((y - y_hat)**2)
    ss_tot = np.sum((y - y.mean())**2)
    r2 = 1 - ss_res/ss_tot if ss_tot > 1e-15 else float('nan')
    print(f"  [{label}] n={len(y):4d}  J={J:.6f} kg·m²  B={B:.6f} Nm·s/rad  R²={r2:.4f}")
    return J, B, r2


