t_alpha_m = t_alpha[t_mask]

# Interpolate current and volts to velocity timestamps
t_curr_interp  = nearest_interp(t_ts_m, turret_curr_ts, turret_curr_val)
t_volts_interp = nearest_interp(t_ts_m, turret_volts_ts, turret_volts_val)

# Signed torque: direction from applied volts sign, magnitude from current
t_tau = tau_scale_t * np.sign(t_volts_interp) * t_curr_interp

# OLS with alpha threshold 1.0 rad/s²
J_t, B_t, r2_t = ols(t_alpha_m, t_vel_sm, t_tau, alpha_thresh=1.0, label="Turret")
print()


# ═══════════════════════════════════════════════════════════════════════════════
# FLYWHEEL regression
# ═══════════════════════════════════════════════════════════════════════════════
print("=" * 60)
print("FLYWHEEL  (2x Kraken, G=1, kt=0.01940, r=0.0381 m)")
print("=" * 60)

G_f, n_f, kt_f, r_f = 1.0, 2.0, 0.01940, 0.0381
tau_scale_f = G_f * n_f * kt_f   # 0.0388 Nm/A

f_ts  = np.array(fly_vel_ts)
f_vel = np.array(fly_vel_val)

# Convert linear → angular
f_omega = f_vel / r_f
# Smooth and differentiate
f_omega_s = smooth(f_omega, w=3)
f_alpha   = np.gradient(f_omega_s, f_ts)  # rad/s²

# Interpolate current to velocity timestamps
f_curr_interp = nearest_interp(f_ts, fly_curr_ts, fly_curr_val)
# Smooth current too (TalonFX aliasing)
f_curr_s = smooth(f_curr_interp, w=2)

f_tau = tau_scale_f * f_curr_s

# Restrict to spin-up window (t≤419.5) for cleaner signal — plateau data adds noise
f_spinup   = f_ts <= 419.5
f_ts_su    = f_ts[f_spinup]
f_omega_su = f_omega_s[f_spinup]
f_alpha_su = f_alpha[f_spinup]
f_tau_su   = f_tau[f_spinup]

# OLS — spin-up window only, higher alpha threshold
J_f, B_f, r2_f = ols(f_alpha_su, f_omega_su, f_tau_su, alpha_thresh=30.0, label="Flywheel")
print()


# ═══════════════════════════════════════════════════════════════════════════════
# KICKER regression (transient windows only)
# ═══════════════════════════════════════════════════════════════════════════════
print("=" * 60)
print("KICKER  (NEO Vortex, G=1, kt=0.01706, r=0.0381 m)")
print("=" * 60)

tau_scale_k = 1.0 * 1.0 * 0.01706
r_k = 0.0381

results_k = []
for idx, (v_ts, v_val, c_ts, c_val) in enumerate([
    (kicker_vel_ts_t1, kicker_vel_val_t1, kicker_curr_ts_t1, kicker_curr_val_t1),
    (kicker_vel_ts_t2, kicker_vel_val_t2, kicker_curr_ts_t2, kicker_curr_val_t2),
]):
    v_ts = np.array(v_ts); v_val = np.array(v_val)
    omega = v_val / r_k
    alpha = np.gradient(omega, v_ts)
    curr  = nearest_interp(v_ts, c_ts, c_val)
    tau   = tau_scale_k * curr
    res = ols(alpha, omega, tau, alpha_thresh=5.0, label=f"Kicker T{idx+1}")
    if res[0] is not None:
        results_k.append(res[0])  # collect J

if results_k:
    J_k = float(np.median(results_k))
    print(f"  [Kicker] combined J estimate = {J_k:.6f} kg·m²")
print()


# ═══════════════════════════════════════════════════════════════════════════════
# SPINDEXER regression (transient windows only)
# ═══════════════════════════════════════════════════════════════════════════════
print("=" * 60)
print("SPINDEXER  (NEO Vortex, G=1, kt=0.01706, r=0.0762 m)")
print("=" * 60)

tau_scale_s = 1.0 * 1.0 * 0.01706
r_s = 0.0762

results_s = []
for idx, (v_ts, v_val, c_ts, c_val) in enumerate([
    (spindexer_vel_ts_t1, spindexer_vel_val_t1, spindexer_curr_ts_t1, spindexer_curr_val_t1),
    (spindexer_vel_ts_t2, spindexer_vel_val_t2, spindexer_curr_ts_t2, spindexer_curr_val_t2),
]):
    v_ts = np.array(v_ts); v_val = np.array(v_val)
    omega = v_val / r_s
    alpha = np.gradient(omega, v_ts)
    curr  = nearest_interp(v_ts, c_ts, c_val)
    tau   = tau_scale_s * curr
    res = ols(alpha, omega, tau, alpha_thresh=3.0, label=f"Spindexer T{idx+1}")
    if res[0] is not None:
        results_s.append(res[0])

if results_s:
    J_s = float(np.median(results_s))
    print(f"  [Spindexer] combined J estimate = {J_s:.6f} kg·m²")
print()


